    JUNCTION_A: 0,
    JUNCTION_B: 0,
    JUNCTION_C: 0,
    JUNCTION_D: 0
};

let data = [];

junctions.forEach(junction => {

    let trafficCount = mqttCounts[junction] || 0;

    let congestion;
    let greenTime;
    let status;
    let signal;
    let incident = false;

    // ==========================
    // MANUAL OVERRIDE
    // ==========================
    if (
        junction === manualJunction &&
        manualSignal &&
        manualSignal !== "AUTO"
    ) {

        congestion = "MANUAL";
        greenTime = 90;
        status = "MANUAL OVERRIDE";
        signal = manualSignal;

    }
    // ==========================
    // EMERGENCY PRIORITY
    // ==========================
    else if (
        emergencyMode &&
        junction === emergencyJunction
    ) {

        congestion = "EMERGENCY";
        greenTime = 90;
        status = "PRIORITY";
        signal = "GREEN";

    }
    // ==========================
    // NORMAL TRAFFIC LOGIC
    // ==========================
    else if (trafficCount <= 5) {

        congestion = "LOW";
        greenTime = 20;
        status = "NORMAL";
        signal = "GREEN";

    }
    else if (trafficCount <= 12) {

        congestion = "MEDIUM";
        greenTime = 40;
        status = "BUSY";
        signal = "AMBER";

    }
    else {

        congestion = "HIGH";
        greenTime = 60;
        status = "CONGESTED";
        signal = "RED";

    }

    // ==========================
    // INCIDENT DETECTION
    // (Don't override manual/emergency)
    // ==========================
    if (
        status !== "MANUAL OVERRIDE" &&
        status !== "PRIORITY" &&
        trafficCount >= 35
    ) {

        incident = true;
        status = "INCIDENT";
        signal = "RED";

    }

    const isEmergencyJunction =
        emergencyMode &&
        junction === emergencyJunction;

    const isManualOverride =
        junction === manualJunction &&
        manualSignal &&
        manualSignal !== "AUTO";

    data.push({
        junction,
        trafficCount,
        congestion,
        greenTime,
        status,
        signal,
        incident,
        isEmergencyJunction,
        isManualOverride
    });

});

flow.set("trafficData", data);

